sql.if:
and exists (
    select 1 from fd_department dscope
    where (dscope.del_flag = 0 or dscope.del_flag is null)
      and dscope.tenant_id = #{tenantId}
      and (
        (m.visit_kind = 'INPATIENT' and trim(dscope.his_id) = trim(m.dept_code))
        or
        (m.visit_kind = 'OUTPATIENT' and trim(dscope.his_id) = trim(m.clinic_code))
      )
      and dscope.id in (
        select distinct x.did from (
            select cast(upd.dept_id as unsigned) as did
            from sb_user_permission_dept upd
            where upd.user_id = #{params.scopeDeptUserId}
              and ifnull(upd.del_flag, '0') = '0'

              and upd.customer_id = #{params.scopeDeptCustomerId}

            union
            select ud.department_id as did
            from sys_user_department ud
            where ud.user_id = #{params.scopeDeptUserId}
              and (ud.status = 0 or ud.status = '0' or ud.status is null)
        ) x
        where x.did is not null
      )
)

mapper.sql:
where m.tenant_id = #{tenantId}
 and m.visit_kind = #{visitKind}
 and m.patient_name like concat('%', #{patientName}, '%')

    and m.inpatient_no like concat('%', #{inpatientNo}, '%')


    and m.outpatient_no like concat('%', #{outpatientNo}, '%')


    and (m.inpatient_no like concat('%', #{visitNo}, '%') or m.outpatient_no like concat('%', #{visitNo}, '%'))

 and m.charge_item_id = #{chargeItemId}



            and trim(ifnull(m.his_inpatient_charge_id,'')) = trim(#{hisChargeId})


            and trim(ifnull(m.his_outpatient_charge_id,'')) = trim(#{hisChargeId})


            and (
                (m.visit_kind = 'INPATIENT' and trim(ifnull(m.his_inpatient_charge_id,'')) = trim(#{hisChargeId}))
                or (m.visit_kind = 'OUTPATIENT' and trim(ifnull(m.his_outpatient_charge_id,'')) = trim(#{hisChargeId}))
            )






            and trim(ifnull(m.his_inpatient_charge_id_tf,'')) = trim(#{chargeIdTf})


            and trim(ifnull(m.his_outpatient_charge_id_tf,'')) = trim(#{chargeIdTf})


            and (
                (m.visit_kind = 'INPATIENT' and trim(ifnull(m.his_inpatient_charge_id_tf,'')) = trim(#{chargeIdTf}))
                or (m.visit_kind = 'OUTPATIENT' and trim(ifnull(m.his_outpatient_charge_id_tf,'')) = trim(#{chargeIdTf}))
            )




    and exists (
        select 1 from fd_department dsel
        where (dsel.del_flag = 0 or dsel.del_flag is null)
          and dsel.tenant_id = #{tenantId}
          and dsel.id = #{departmentId}
          and (
            (m.visit_kind = 'INPATIENT' and trim(dsel.his_id) = trim(m.dept_code))
            or (m.visit_kind = 'OUTPATIENT' and trim(dsel.his_id) = trim(m.clinic_code))
          )
    )


    and m.process_status != 'PENDING_CONSUME'


    and m.process_status = 'PENDING_CONSUME'

 and m.charge_at >= #{beginChargeDate}
 and m.charge_at <= #{endChargeDate}
 and m.process_time >= #{beginProcessTime}
 and m.process_time <= #{endProcessTime}
 and () = #{valueLevel}

    and () in
    #{vl}


    and m.dept_name like concat('%', #{deptNameLike}, '%')


    and m.clinic_name like concat('%', #{clinicNameLike}, '%')


    and (m.dept_name like concat('%', #{deptNameLike}, '%') or m.clinic_name like concat('%', #{deptNameLike}, '%'))
